VALUES
  ('social-worker-moex-04200', 'social-worker', 'social-worker-moex-111-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關績效管理之目標管理型態系統（MBO-type system）及績效監測型態系統（PM-type system），下列敘述何者正確？', '["目標管理型態系統將焦點置於個別管理者和員工的績效，是一種較著重個人化的過程", "績效監測型態系統較紮根於人事系統", "目標管理型態系統的標的往往是基於以往績效由高層單方所設定的", "績效監測型態系統著重於輸出、立即成果，較不強調品質與顧客服務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:24+00:00", "source_pdf_sha1": "ce38bf0a4fd9", "answer_pdf_sha1": "ad6a3199dde2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04201', 'social-worker', 'social-worker-moex-111-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關目標管理之意涵，下列敘述何者錯誤？', '["管理者以工作「目標」來管理部屬，而不是以「手段」或「程序」來管理部屬", "藉由管理者和部屬共同設定與組織目標相關的個別目標，讓部屬有充分的自由來選擇達成 目標的最佳手段", "偏向X理論，認為應嚴格管控，員工才能達到目標，強調目標達成的重要性", "管理者將以原定目標與部屬之實際執行成果核對，並決定糾正、調整和獎懲，以確保目標的 達成"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:24+00:00", "source_pdf_sha1": "ce38bf0a4fd9", "answer_pdf_sha1": "ad6a3199dde2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04202', 'social-worker', 'social-worker-moex-111-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '以組織管理的目標而言，①經費  ②投入  ③活動  ④產出  ⑤結果；效能（effectiveness） 介於下列何者之間？', '["", "", "之間", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:24+00:00", "source_pdf_sha1": "ce38bf0a4fd9", "answer_pdf_sha1": "ad6a3199dde2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 30, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04203', 'social-worker', 'social-worker-moex-111-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「治理」（governance）一詞最早出現於世界銀行提出的「治理危機」，之後便受到各領域的廣 泛討論，有關治理之特點，下列敘述何者錯誤？', '["網絡成員之間互動的持續", "以信任為基礎的互動關係", "須對國家負責，自主性低", "組織之間的相互依賴，界線較容易更動與模糊"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:24+00:00", "source_pdf_sha1": "ce38bf0a4fd9", "answer_pdf_sha1": "ad6a3199dde2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04204', 'social-worker', 'social-worker-moex-111-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列敘述何者為工作團隊（work team）之特徵？①目標為集體績效  ②目標為分享資訊', '["責信為個人的", "責信為個人及相互的  ⑤技能為隨機與變化的  ⑥技能為互補的", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:24+00:00", "source_pdf_sha1": "ce38bf0a4fd9", "answer_pdf_sha1": "ad6a3199dde2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 32, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04205', 'social-worker', 'social-worker-moex-111-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關衝突（conflict）之意涵與觀點，下列敘述何者錯誤？', '["若衝突能夠被妥善處理，衝突可促進組織目標的達成", "衝突的共同特點包含：對立性、稀有性及阻撓性", "衝突的人際觀點認為，管理者的責任是消除團體中可能造成的衝突，並即時予以化解", "衝突的互動觀點認為，衝突對於團體有正面的效益，且是絕對必要的"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:24+00:00", "source_pdf_sha1": "ce38bf0a4fd9", "answer_pdf_sha1": "ad6a3199dde2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04206', 'social-worker', 'social-worker-moex-111-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '當個體同時為兩種或兩種以上的目標所吸引，而造成個體只能選擇其中一種目標時所產生的 內心衝突，係指下列何種衝突？', '["雙趨衝突（approach-approachconflict）", "雙避衝突（avoidance-avoidanceconflict）", "趨避衝突（approach-avoidanceconflict）", "多重趨避衝突（multiple-avoidanceconflict）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:24+00:00", "source_pdf_sha1": "ce38bf0a4fd9", "answer_pdf_sha1": "ad6a3199dde2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04207', 'social-worker', 'social-worker-moex-111-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '一種管理過程，由管理階層設計並由董事會核准，藉以合理確保可靠財務報導、有效率及效 果之營運、法令之遵循，屬於下列何種財務管控方式？', '["外部控制", "法定控管", "內部控制", "定期控管"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:24+00:00", "source_pdf_sha1": "ce38bf0a4fd9", "answer_pdf_sha1": "ad6a3199dde2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04208', 'social-worker', 'social-worker-moex-111-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '相較於行銷，有關公共關係的特性，下列敘述何者錯誤？', '["公共關係主要是一種溝通工具", "公共關係企圖影響特定的行為", "公共關係是手段而非目的", "公共關係的功能，是要讓大眾知道組織的成就"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:24+00:00", "source_pdf_sha1": "ce38bf0a4fd9", "answer_pdf_sha1": "ad6a3199dde2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04209', 'social-worker', 'social-worker-moex-111-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '行銷（marketing）有助於社會福利組織使命、願景目標的達成。有關卓越行銷的核心關鍵， 下列敘述何者錯誤？', '["詢問服務使用者的需要，重視他們的回答並予以回應", "只以社會工作專業為中心，低估服務使用者意見的價值", "發展衡量成果的基準及指標作為評估之用", "訓練工作人員提高對服務使用者意見的敏感度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:24+00:00", "source_pdf_sha1": "ce38bf0a4fd9", "answer_pdf_sha1": "ad6a3199dde2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
